tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Run segmentation sopa segmentation #if $method.method_name == 'cellpose' cellpose "\${SDATA_DIR}" #for $channel in str($method.channels).split(',') --channels '$channel' #end for --diameter $method.diameter #if str($method.model_type) != '' --model-type '$method.model_type' #end if #if str($method.pretrained_model) != '' --pretrained-model '$method.pretrained_model' #end if --min-area $method.min_area --flow-threshold $method.flow_threshold --cellprob-threshold $method.cellprob_threshold #if $method.gaussian_sigma --gaussian-sigma $method.gaussian_sigma #end if #if $method.clip_limit --clip-limit $method.clip_limit #end if #if $method.clahe_kernel_size --clahe-kernel-size $method.clahe_kernel_size #end if #if str($method.resample) == 'no' --method-kwargs '{"resample": False}' #end if #if str($method.patch_index) != '' --patch-index $method.patch_index #end if #if str($method.cache_dir_name) != '' --cache-dir-name '$method.cache_dir_name' #end if #else if $method.method_name == 'stardist' stardist "\${SDATA_DIR}" #if str($method.model_type) != '' --model-type '$method.model_type' #end if #if str($method.local_model) != '' --local-model '$method.local_model' #end if --prob-thresh $method.prob_thresh --nms-thresh $method.nms_thresh #if str($method.channels) != '' --channels '$method.channels' #end if --min-area $method.min_area #if $method.clip_limit --clip-limit $method.clip_limit #end if #if $method.clahe_kernel_size --clahe-kernel-size $method.clahe_kernel_size #end if #if $method.gaussian_sigma --gaussian-sigma $method.gaussian_sigma #end if #if str($method.patch_index) != '' --patch-index $method.patch_index #end if #if str($method.cache_dir_name) != '' --cache-dir-name '$method.cache_dir_name' #end if #if str($method.method_kwargs) != '' --method-kwargs '$method.method_kwargs' #end if #else if $method.method_name == 'comseg' comseg "\${SDATA_DIR}" #if str($method.config) != '' --config '$method.config' #end if #if str($method.patch_index) != '' --patch-index $method.patch_index #end if --min-area $method.min_area #else if $method.method_name == 'baysor' baysor "\${SDATA_DIR}" #if $method.config_source.source == 'file' --config '$method.config_source.config_file' #else --config '$method.config_source.config_text' #end if #if str($method.prior_shapes_key) != '' --prior-shapes-key '$method.prior_shapes_key' #end if #if str($method.patch_index) != '' --patch-index $method.patch_index #end if --min-area $method.min_area #if str($method.scale) != '' --scale $method.scale #end if #else if $method.method_name == 'proseg' proseg "\${SDATA_DIR}" #if str($method.command_line_suffix) != '' --command-line-suffix '$method.command_line_suffix' #end if #if $method.infer_presets == 'no' --no-infer-presets #end if #if str($method.prior_shapes_key) != '' --prior-shapes-key '$method.prior_shapes_key' #end if #if str($method.bins_key) != '' --bins-key '$method.bins_key' #end if #else if $method.method_name == 'tissue' tissue "\${SDATA_DIR}" #if str($method.image_key) != '' --image-key '$method.image_key' #end if --level $method.level #if str($method.mode) != '' --mode '$method.mode' #end if #if str($method.kwargs) != '' --kwargs '$method.kwargs' #end if #else if $method.method_name == 'generic-staining' generic-staining "\${SDATA_DIR}" --method-name '$method.method_name_generic' #if str($method.method_kwargs) != '' --method-kwargs '$method.method_kwargs' #end if #if str($method.channels) != '' --channels '$method.channels' #end if --min-area $method.min_area #if $method.clip_limit --clip-limit $method.clip_limit #end if #if $method.clahe_kernel_size --clahe-kernel-size $method.clahe_kernel_size #end if #if $method.gaussian_sigma --gaussian-sigma $method.gaussian_sigma #end if #if str($method.patch_index) != '' --patch-index $method.patch_index #end if #if str($method.cache_dir_name) != '' --cache-dir-name '$method.cache_dir_name' #end if #end if &&
## Move to output directory mv "input/spatialdata.zarr" output_dir/ &&
@CMD_ZIP_ZARR@
